#!/usr/bin/env python3
import csv
import json
import os
import datetime
from collections import defaultdict

SCHEMA_PATH = os.path.join('/app','schema.json')
DATA_DIR = os.path.join('/app','data')
OUT_PATH = os.path.join('/app','organization.json')


def read_csv(path):
    with open(path, newline='', encoding='utf-8') as f:
        return list(csv.DictReader(f))


def load_schema(path):
    try:
        with open(path, 'r', encoding='utf-8') as f:
            return json.load(f)
    except Exception:
        return {}


def norm_key_lookup(keys, candidates):
    """Return the first matching key from candidates (case-insensitive)."""
    lower_map = {k.lower(): k for k in candidates}
    for key in keys:
        if key in candidates:
            return key
        lk = key.lower()
        if lk in lower_map:
            return lower_map[lk]
    return None


def find_key_by_contains(candidates, includes):
    """Find a key in candidates whose lowercase contains any token in includes."""
    lcands = [c.lower() for c in candidates]
    for token in includes:
        for i, lc in enumerate(lcands):
            if token in lc:
                return list(candidates)[i]
    return None


def to_int(val, default=None):
    try:
        if val is None or val == '':
            return default
        return int(val)
    except Exception:
        try:
            return int(float(val))
        except Exception:
            return default


def to_float(val, default=None):
    try:
        if val is None or val == '':
            return default
        return float(val)
    except Exception:
        return default


def main():
    schema = load_schema(SCHEMA_PATH)

    departments_csv = read_csv(os.path.join(DATA_DIR, 'departments.csv'))
    employees_csv = read_csv(os.path.join(DATA_DIR, 'employees.csv'))
    projects_csv = read_csv(os.path.join(DATA_DIR, 'projects.csv'))

    # Determine department fields
    dept_fields = departments_csv[0].keys() if departments_csv else []
    dept_id_key = norm_key_lookup(['id','department_id','dept_id'], dept_fields) or find_key_by_contains(dept_fields, ['dept', 'department']) or 'id'
    dept_name_key = norm_key_lookup(['name','department_name'], dept_fields) or 'name'
    dept_manager_key = norm_key_lookup(['manager','manager_name'], dept_fields)

    # Determine employee fields
    emp_fields = employees_csv[0].keys() if employees_csv else []
    emp_id_key = norm_key_lookup(['id','employee_id'], emp_fields) or 'id'
    emp_name_key = norm_key_lookup(['name','employee_name'], emp_fields) or 'name'
    emp_title_key = norm_key_lookup(['title','role','position'], emp_fields)
    emp_salary_key = norm_key_lookup(['salary','compensation','pay'], emp_fields)
    emp_dept_key = norm_key_lookup(['department_id','dept_id','department'], emp_fields) or find_key_by_contains(emp_fields, ['dept', 'department'])

    # Determine project fields
    proj_fields = projects_csv[0].keys() if projects_csv else []
    proj_id_key = norm_key_lookup(['id','project_id'], proj_fields) or 'id'
    proj_name_key = norm_key_lookup(['name','project_name'], proj_fields) or 'name'
    proj_budget_key = norm_key_lookup(['budget','cost','allocation'], proj_fields)
    proj_dept_key = norm_key_lookup(['department_id','dept_id','department'], proj_fields) or find_key_by_contains(proj_fields, ['dept', 'department'])

    # Group employees and projects by department
    emp_by_dept = defaultdict(list)
    for e in employees_csv:
        dept_id = str(e.get(emp_dept_key)) if emp_dept_key else ''
        employee = {
            'id': e.get(emp_id_key),
            'name': e.get(emp_name_key),
            'title': e.get(emp_title_key),
            'salary': to_float(e.get(emp_salary_key), None)
        }
        emp_by_dept[dept_id].append(employee)

    proj_by_dept = defaultdict(list)
    for p in projects_csv:
        dept_id = str(p.get(proj_dept_key)) if proj_dept_key else ''
        project = {
            'id': p.get(proj_id_key),
            'name': p.get(proj_name_key),
            'budget': to_float(p.get(proj_budget_key), None)
        }
        proj_by_dept[dept_id].append(project)

    # Build departments output with stats
    departments_out = []
    total_employees = 0
    total_projects = 0
    total_salary = 0.0
    total_budget = 0.0

    for d in departments_csv:
        dept_id_val = d.get(dept_id_key)
        dept_id_str = str(dept_id_val) if dept_id_val is not None else ''
        dept_name = d.get(dept_name_key) or f"Department {dept_id_str}"
        manager = d.get(dept_manager_key) if dept_manager_key else None

        employees = emp_by_dept.get(dept_id_str, [])
        projects = proj_by_dept.get(dept_id_str, [])

        emp_count = len(employees)
        proj_count = len(projects)
        total_employees += emp_count
        total_projects += proj_count

        dept_salary_sum = sum([e['salary'] for e in employees if isinstance(e.get('salary'), (int, float))])
        dept_budget_sum = sum([p['budget'] for p in projects if isinstance(p.get('budget'), (int, float))])
        total_salary += dept_salary_sum
        total_budget += dept_budget_sum
        avg_salary = (dept_salary_sum / emp_count) if emp_count > 0 else None

        dept_out = {
            'id': dept_id_str,
            'name': dept_name,
            'manager': manager,
            'employees': employees,
            'projects': projects,
            'stats': {
                'employee_count': emp_count,
                'project_count': proj_count,
                'total_salary': dept_salary_sum,
                'total_project_budget': dept_budget_sum,
                'average_salary': avg_salary
            }
        }
        departments_out.append(dept_out)

    # Organization metadata - attempt to use schema title/name if available
    org_name = None
    if isinstance(schema, dict):
        org_name = schema.get('title') or schema.get('name')
    if not org_name:
        org_name = 'Organization'

    org_stats = {
        'department_count': len(departments_out),
        'employee_count': total_employees,
        'project_count': total_projects,
        'total_salary': total_salary,
        'total_project_budget': total_budget,
        'average_salary': (total_salary / total_employees) if total_employees > 0 else None
    }

    output = {
        'organization': {
            'name': org_name,
            'generated_at': datetime.datetime.utcnow().isoformat() + 'Z',
            'stats': org_stats
        },
        'departments': departments_out
    }

    with open(OUT_PATH, 'w', encoding='utf-8') as f:
        json.dump(output, f, indent=2, ensure_ascii=False)


if __name__ == '__main__':
    main()
PY
